1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	const COMPONENT_PREMIUM = 25;
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const MAIN_ITEM_PREMIUM: Record<string, number> = {
45	  sword: 100,
46	  amulet: 60,
47	  staff: 80,
48	  potion: 40,
49	};
50	
51	const INSURANCE_VALUE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
63	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
64	
65	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOWUP_DISCOUNT_RATE = 0.15;
72	const PROCESSING_FEE = 5;
73	const ROUNDING_PRECISION = 6;
74	
75	const roundTo = (value: number, direction: "up" | "down"): number => {
76	  const fixed = Number(value.toFixed(ROUNDING_PRECISION));
77	  return direction === "up" ? Math.ceil(fixed) : Math.floor(fixed);
78	};
79	
80	const componentBasePremium = (count: number): number => {
81	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
82	  return count * COMPONENT_PREMIUM;
83	};
84	
85	const COMPONENT_TYPES = ["rune", "moonstone"];
86	
87	const countByType = (items: Item[]): Map<string, number> => {
88	  const counts = new Map<string, number>();
89	  for (const { type } of items) {
90	    if (COMPONENT_TYPES.includes(type)) {
91	      counts.set(type, (counts.get(type) ?? 0) + 1);
92	    }
93	  }
94	  return counts;
95	};
96	
97	const componentsBasePremium = (items: Item[]): number => {
98	  const counts = [...countByType(items).values()];
99	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
100	};
101	
102	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
103	
104	const mainItemsBasePremium = (items: Item[]): number =>
105	  items.reduce((total, item) => total + itemBasePremium(item), 0);
106	
107	const policyBasePremium = (items: Item[]): number =>
108	  mainItemsBasePremium(items) + componentsBasePremium(items);
109	
110	const isHighEnchantment = (item: Item): boolean =>
111	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
112	
113	const itemSurcharge = (item: Item): number => {
114	  const base = itemBasePremium(item);
115	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
116	  const highEnchant = isHighEnchantment(item)
117	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
118	    : 0;
119	  return curse + highEnchant;
120	};
121	
122	const itemSurcharges = (items: Item[]): number =>
123	  items.reduce((total, item) => total + itemSurcharge(item), 0);
124	
125	const isLoyalCustomer = (customer: Customer): boolean =>
126	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
127	
128	const loyaltyDiscount = (base: number, customer: Customer): number =>
129	  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
130	
131	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
132	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
133	
134	const quotePremium = (
135	  items: Item[],
136	  customer: Customer,
137	  isFollowUp: boolean,
138	): number => {
139	  const base = policyBasePremium(items);
140	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
141	  const total =
142	    base +
143	    itemSurcharges(items) +
144	    firstInsurance -
145	    loyaltyDiscount(base, customer) -
146	    followUpDiscount(base, isFollowUp) +
147	    PROCESSING_FEE;
148	  return roundTo(total, "up");
149	};
150	
151	const insuranceSum = (items: Item[]): number =>
152	  items.reduce((total, item) => total + (INSURANCE_VALUE[item.type] ?? 0), 0);
153	
154	const reimbursement = (amount: number, insuredItem: Item): number =>
155	  (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
156	    ? HIGH_ENCHANTMENT_PAYOUT_RATE * amount
157	    : amount;
158	
159	const damagePayout = (damage: Damage, insuredItem: Item): number =>
160	  reimbursement(damage.amount, insuredItem) - DEDUCTIBLE;
161	
162	const payoutForDamage = (damage: Damage, items: Item[]): number => {
163	  const insuredItem = items.find((item) => item.type === damage.itemType) as Item;
164	  return damagePayout(damage, insuredItem);
165	};
166	
167	const incidentPayout = (incident: Incident, items: Item[]): number =>
168	  incident.damages.reduce(
169	    (total, damage) => total + payoutForDamage(damage, items),
170	    0,
171	  );
172	
173	const initialCap = (items: Item[]): number =>
174	  CAP_MULTIPLIER * insuranceSum(items);
175	
176	const tally = (types: string[]): Map<string, number> => {
177	  const counts = new Map<string, number>();
178	  for (const type of types) {
179	    counts.set(type, (counts.get(type) ?? 0) + 1);
180	  }
181	  return counts;
182	};
183	
184	const validateDamageCounts = (incident: Incident, items: Item[]): void => {
185	  const insured = tally(items.map((item) => item.type));
186	  const damaged = tally(incident.damages.map((damage) => damage.itemType));
187	  for (const [type, count] of damaged) {
188	    if (count > (insured.get(type) ?? 0)) {
189	      throw new Error(`claim references more ${type} than insured`);
190	    }
191	  }
192	};
193	
194	const claimResult = (
195	  step: ClaimStep,
196	  scenario: Scenario,
197	  remainingCapByPolicy: Map<number, number>,
198	): { payout: number; remainingCap: number } => {
199	  const policy = scenario.steps[step.policy] as QuoteStep;
200	  validateDamageCounts(step.incident, policy.items);
201	  const remainingCap =
202	    remainingCapByPolicy.get(step.policy) ?? initialCap(policy.items);
203	  const rawPayout = incidentPayout(step.incident, policy.items);
204	  const payout = roundTo(Math.min(rawPayout, remainingCap), "down");
205	  const newRemainingCap = remainingCap - payout;
206	  remainingCapByPolicy.set(step.policy, newRemainingCap);
207	  return { payout, remainingCap: newRemainingCap };
208	};
209	
210	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
211	  let quoteCount = 0;
212	  const remainingCapByPolicy = new Map<number, number>();
213	  const results = scenario.steps.map((step) => {
214	    if (step.op === "claim") {
215	      return claimResult(step, scenario, remainingCapByPolicy);
216	    }
217	    const isFollowUp = quoteCount > 0;
218	    quoteCount += 1;
219	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
220	  });
221	  return { results };
222	};
